/**
 * Converts a string of HTML into Markdown.
 * @param {string} html - The HTML content to convert.
 * @returns {string} - The converted Markdown text.
 */
function htmlToMarkdown(html) {
  if (!html) return '';

  let markdown = html
    // Handle special shortcodes by removing them
    .replace(/\[rank_math_breadcrumb\]/g, '')
    .replace(/\[archive-location\]/g, '')
    // Handle headings
    .replace(/<h1>(.*?)<\/h1>/gi, '# $1\n')
    .replace(/<h2>(.*?)<\/h2>/gi, '## $1\n')
    .replace(/<h3>(.*?)<\/h3>/gi, '### $1\n')
    .replace(/<h4>(.*?)<\/h4>/gi, '#### $1\n')
    .replace(/<h5>(.*?)<\/h5>/gi, '##### $1\n')
    .replace(/<h6>(.*?)<\/h6>/gi, '###### $1\n')
    // Handle paragraphs
    .replace(/<p>(.*?)<\/p>/gi, '$1\n\n')
    // Handle links
    .replace(/<a href="([^"]+)"[^>]*>(.*?)<\/a>/gi, '[$2]($1)')
    // Handle unordered lists
    .replace(/<ul>/gi, '')
    .replace(/<\/ul>/gi, '')
    .replace(/<li>(.*?)<\/li>/gi, '- $1\n')
    // Handle blockquotes
    .replace(/<blockquote>/gi, '> ')
    .replace(/<\/blockquote>/gi, '\n')
    // Handle bold and strong tags
    .replace(/<strong>(.*?)<\/strong>/gi, '**$1**')
    .replace(/<b>(.*?)<\/b>/gi, '**$1**')
    // Handle line breaks
    .replace(/<br\s*\/?>/gi, '\n')
    // Strip any remaining HTML tags (like divs, svgs, etc.)
    .replace(/<[^>]+>/g, '')
    // Decode HTML entities
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    // Clean up extra whitespace and newlines
    .trim();

  return markdown;
}

/**
 * Converts the full JSON data structure into a formatted Markdown string.
 * @param {Array} jsonData - The JSON data array.
 * @returns {string} - The complete Markdown output.
 */
function convertJsonToMarkdown(jsonData) {
  const data = jsonData;
  if (!data) return "No data found.";

  let markdownOutput = "";

  // 1. Website Information
  const siteInfo = data.website;
  if (siteInfo) {
    markdownOutput += `# ${siteInfo.website_name}\n`;
    markdownOutput += `**URL:** [${siteInfo.website_url}](${siteInfo.website_url})\n`;
    if (siteInfo.website_description) {
      markdownOutput += `**Description:** ${siteInfo.website_description}\n`;
    }
    markdownOutput += `**Language:** ${siteInfo.website_language}\n\n`;
  }

  // 2. Content Sections
  const contentSections = data.content;
  contentSections.forEach(section => {
    markdownOutput += `---\n`;
    markdownOutput += `## ${section.name}\n\n`;

    // Handle Posts Content with Categories
    if (section.key === 'post' && section.category) {
      markdownOutput += `### Categories\n`;
      section.category.forEach(cat => {
        markdownOutput += `- ${cat.replace(/&amp;/g, '&')}\n`;
      });
      markdownOutput += `\n`;
    }

    // Handle all posts/pages within a section
    if (section.posts && section.posts.length > 0) {
      section.posts.forEach(post => {
        // Use H3 for post titles for better hierarchy
        markdownOutput += `### ${post.title}\n\n`;
        // Convert the HTML content to Markdown
        markdownOutput += `${htmlToMarkdown(post.content)}\n\n`;
      });
    }
  });

  return markdownOutput;
}

const markdownResult = convertJsonToMarkdown($input.first().json.data);
return {markdown: markdownResult}

function getValidJsonObject(rawText) {
    if (typeof rawText !== 'string' || rawText.trim() === '') {
        console.log("Invalid input or empty text field.");
        return null;
    }
    let jsonString = rawText.trim();
    // Extract JSON from markdown code block fences if present
    const markdownRegex = /```(?:json)?\s*([\s\S]*?)\s*```/;
    const match = jsonString.match(markdownRegex);
    if (match) {
        jsonString = match[1].trim();
    }
    // First attempt: try parsing as-is
    try {
        return JSON.parse(jsonString);
    } catch (firstError) {
        console.log("First parse attempt failed, trying to fix unescaped quotes...");

        // Fix unescaped quotes within string values
        // Strategy: Process character by character, tracking if we're inside a JSON string
        let fixedString = fixUnescapedQuotes(jsonString);

        try {
            return JSON.parse(fixedString);
        } catch (secondError) {
            console.log("All parse attempts failed:", secondError);
            console.log("Problematic string (first 500 chars):", jsonString.substring(0, 500));
            return null;
        }
    }
}
function fixUnescapedQuotes(jsonString) {
    let result = '';
    let inString = false;
    let i = 0;

    while (i < jsonString.length) {
        const char = jsonString[i];
        const prevChar = i > 0 ? jsonString[i - 1] : '';
        const nextChar = i < jsonString.length - 1 ? jsonString[i + 1] : '';

        if (char === '"') {
            if (!inString) {
                // Opening quote of a JSON string value
                inString = true;
                result += char;
            } else if (prevChar === '\\') {
                // Already escaped quote inside string - keep it
                result += char;
            } else {
                // We're inside a string and found an unescaped quote
                // Check if this is the closing quote or an unescaped quote in content

                // Heuristic: If next chars look like JSON structure, it's a closing quote
                // Look for patterns like: ", or ": or "} or "] or just end
                const afterQuote = jsonString.substring(i + 1, i + 3).trim();
                const isClosingQuote = 
                    afterQuote.startsWith(',') || 
                    afterQuote.startsWith(':') || 
                    afterQuote.startsWith('}') || 
                    afterQuote.startsWith(']') ||
                    afterQuote === '' ||
                    afterQuote.startsWith('\n');

                if (isClosingQuote) {
                    // This is the actual closing quote
                    inString = false;
                    result += char;
                } else {
                    // This is an unescaped quote inside the string - escape it
                    result += '\\"';
                }
            }
        } else if (char === '\\' && inString && nextChar === '"') {
            // This is an escape sequence for quote, keep as-is
            result += char;
        } else {
            result += char;
        }

        i++;
    }

    return result;
}

// Combine the 'text' from all parts into a single string.
const combinedText = $input.first().json.content.parts.map(part => part.text).join('');

return {data: getValidJsonObject(combinedText)};

function groupBySourceSeedAsArray(data = []) {
  const map = {};

  data.forEach(item => {
    if (!map[item.source_seed]) {
      map[item.source_seed] = [];
    }
    map[item.source_seed].push(item);
  });

  return Object.entries(map).map(([source_seed, items]) => ({
    source_seed,
    items
  }));
}

return groupBySourceSeedAsArray($input.first().json.data);
